insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('32772', 'ja.di', 'jadi', '', '', '["Verba","Verba","Verba","Verba","Verba","Verba","Verba","Partikel"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"langsung berlaku (dilakukan, dikerjakan); tidak batal","contoh":[{"nomor":2,"teks":"kemarin ia -- pergi ke Bogor"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"betul-betul terjadi; menjadi kenyataan (berhasil)","contoh":[{"nomor":2,"teks":"barang kehendaknya --"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"selesai dibuat","contoh":[{"nomor":2,"teks":"rumahnya belum --"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"lahir; dilahirkan","contoh":[{"nomor":2,"teks":"ketika itu engkau baru --"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"sudah selesai dibuat; siap pakai","contoh":[{"nomor":2,"teks":"ia membeli pakaian --"}]},{"nomor":"6","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"baiklah begitu; setuju","contoh":[{"nomor":2,"teks":"kalau begitu --"}]},{"nomor":"7","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"menjadi","contoh":[]},{"nomor":"8","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"oleh sebab itu; maka; dengan demikian","contoh":[{"nomor":2,"teks":"ibunya sakit, -- dia terpaksa pulang"}]}]', '{"text":"[Sanskerta जात jāta a ''yang terjadi, yang timbul, yang muncul, yang tumbuh'']","languages":["Sanskerta"]}', '["jadi-jadian","jadian","jejadian","kejadian","kemenjadian","keterjadian","menjadi","menjadi-jadi","menjadi-jadikan","menjadikan","penjadi","penjadian","sejadi-jadinya","terjadi"]', '["jadi umum"]', '["acap berulang, yang jauh jadi dekat","adat semula jadi","berguru kepalang ajar, bagai bunga kembang tak jadi","bukit jadi paya","buntat hendak jadi kemala","genggam bara api biar sampai jadi arang","iba akan kacang sebuah, tak jadi memengat","jadi abu arang","jadi alas cakap","jadi bumi langit","jadi dinding tasak peti permainan","jadi kain basahan","jadi mata telinga (jadi kaki tangan)","kalah jadi abu, menang jadi arang","kalau ibu kaya, anak jadi putri, kalau anak kaya, ibu jadi budak","kalau pandai menggulai, badar jadi tenggiri","katak hendak jadi lembu","lopak jadi perigi","lupak jadi perigi","rindu jadi batasnya, maka manis tak jadi cuka","secupak tak jadi segantang","secupak tidak akan jadi sesukat, yang sejengkal tidak akan jadi sehasta","sehari selembar benang, lama-lama jadi sehelai kain","sejengkal tak akan jadi sehasta, secupak tak akan jadi sesukat","siapa pun jadi raja, tanganku ke dahi juga","telah jadi indarus","tiada rotan, akar pun berguna (jadi)","yang secupak takkan jadi segantang","yang sesukat tak akan jadi segantang"]', '[]', '[{"peribahasa":"acap berulang, yang jauh jadi dekat","makna":"Sesuatu yang sering diulang-ulang atau dilakukan secara terus-menerus akan menjadi terbiasa dan terasa mudah, bahkan hal yang awalnya sulit atau jauh sekalipun."},{"peribahasa":"adat semula jadi","makna":"Adat atau kebiasaan yang sudah ada sejak dahulu kala dan menjadi bagian tak terpisahkan dari suatu masyarakat."},{"peribahasa":"berguru kepalang ajar, bagai bunga kembang tak jadi","makna":"Belajar atau menuntut ilmu secara tidak tuntas atau setengah-setengah tidak akan menghasilkan sesuatu yang sempurna atau bermanfaat."},{"peribahasa":"bukit jadi paya","makna":"Sesuatu yang awalnya tinggi, mulia, atau berkuasa menjadi rendah, hina, atau tidak berdaya."},{"peribahasa":"buntat hendak jadi kemala","makna":"Seseorang yang tidak memiliki kemampuan atau kualitas yang memadai, tetapi berkeinginan untuk menjadi sesuatu yang besar atau mulia."},{"peribahasa":"genggam bara api biar sampai jadi arang","makna":"Melakukan suatu pekerjaan yang sulit dan penuh risiko dengan sabar dan tabah hingga mencapai hasil yang diinginkan."},{"peribahasa":"iba akan kacang sebuah, tak jadi memengat","makna":"Karena terlalu sayang atau pelit terhadap sesuatu yang kecil, akhirnya kehilangan kesempatan untuk mendapatkan keuntungan yang lebih besar."},{"peribahasa":"jadi abu arang","makna":"Hancur lebur, musnah sama sekali, atau tidak bersisa."},{"peribahasa":"jadi alas cakap","makna":"Menjadi bahan pembicaraan atau gunjingan orang lain."},{"peribahasa":"jadi bumi langit","makna":"Menjadi tumpuan harapan atau tempat bergantung bagi banyak orang."},{"peribahasa":"jadi dinding tasak peti permainan","makna":"Menjadi penghalang atau rintangan yang tidak berarti."},{"peribahasa":"jadi kain basahan","makna":"Menjadi bahan ejekan, hinaan, atau diperlakukan semena-mena."},{"peribahasa":"jadi mata telinga (jadi kaki tangan)","makna":"Menjadi orang kepercayaan atau pembantu setia yang sangat diandalkan."},{"peribahasa":"kalah jadi abu, menang jadi arang","makna":"Dalam suatu pertikaian atau perselisihan, baik yang kalah maupun yang menang sama-sama menderita kerugian."},{"peribahasa":"kalau ibu kaya, anak jadi putri, kalau anak kaya, ibu jadi budak","makna":"Peribahasa ini menggambarkan perbedaan perlakuan dan tanggung jawab antara ibu dan anak. Ketika ibu memiliki harta, anaknya akan hidup senang layaknya seorang putri. Sebaliknya, jika anak yang menjadi kaya, sering kali ibunya justru diperlakukan seperti pembantu atau orang yang harus terus melayani."},{"peribahasa":"kalau pandai menggulai, badar jadi tenggiri","makna":"Jika seseorang memiliki keahlian atau kepandaian, ia dapat mengubah sesuatu yang biasa menjadi luar biasa atau bernilai tinggi."},{"peribahasa":"katak hendak jadi lembu","makna":"Seseorang yang ingin menjadi seperti orang lain yang lebih besar, kuat, atau kaya, padahal ia tidak memiliki kemampuan atau modal yang cukup."},{"peribahasa":"lopak jadi perigi","makna":"Sesuatu yang awalnya kecil atau tidak berarti menjadi besar, penting, atau bermanfaat."},{"peribahasa":"lupak jadi perigi","makna":"Memiliki makna yang sama dengan \"lopak jadi perigi\"."},{"peribahasa":"rindu jadi batasnya, maka manis tak jadi cuka","makna":"Sesuatu yang sangat dirindukan atau diharapkan, meskipun pada akhirnya tidak sesuai dengan harapan, tetap diterima dengan lapang dada."},{"peribahasa":"secupak tak jadi segantang","makna":"Sesuatu yang sudah menjadi takaran atau ukuran tidak akan bisa diubah atau ditambah."},{"peribahasa":"secupak tidak akan jadi sesukat, yang sejengkal tidak akan jadi sehasta","makna":"Memiliki makna yang sama dengan \"secupak tak jadi segantang\", yaitu sesuatu yang sudah menjadi takaran atau ukuran tidak akan bisa diubah atau ditambah."},{"peribahasa":"sehari selembar benang, lama-lama jadi sehelai kain","makna":"Pekerjaan yang dilakukan sedikit demi sedikit secara terus-menerus, pada akhirnya akan menghasilkan sesuatu yang besar dan sempurna."},{"peribahasa":"sejengkal tak akan jadi sehasta, secupak tak akan jadi sesukat","makna":"Memiliki makna yang sama dengan \"secupak tak jadi segantang\", yaitu sesuatu yang sudah menjadi takaran atau ukuran tidak akan bisa diubah atau ditambah."},{"peribahasa":"siapa pun jadi raja, tanganku ke dahi juga","makna":"Siapa pun yang berkuasa atau memimpin, kita harus tetap menghormati dan patuh kepadanya."},{"peribahasa":"telah jadi indarus","makna":"Seseorang yang telah kalah atau kehilangan segalanya."},{"peribahasa":"tiada rotan, akar pun berguna (jadi)","makna":"Jika tidak ada pilihan yang lebih baik, maka yang kurang baik pun dapat dimanfaatkan."},{"peribahasa":"yang secupak takkan jadi segantang","makna":"Memiliki makna yang sama dengan \"secupak tak jadi segantang\", yaitu sesuatu yang sudah menjadi takaran atau ukuran tidak akan bisa diubah atau ditambah."},{"peribahasa":"yang sesukat tak akan jadi segantang","makna":"Memiliki makna yang sama dengan \"secupak tak jadi segantang\", yaitu sesuatu yang sudah menjadi takaran atau ukuran tidak akan bisa diubah atau ditambah."}]');
