alan inspeksi","jalan kabupaten","jalan kelas I","jalan kelas II","jalan kelas III","jalan keluar","jalan kerucut","jalan khusus","jalan kolektor","jalan kolektor primer","jalan kolektor sekunder","jalan kompromi","jalan kota","jalan layang","jalan layang nontol","jalan lepas","jalan lingkar","jalan lingkungan","jalan lintas pemandangan satwa liar","jalan lokal","jalan lurus","jalan masuk","jalan masuk panggung","jalan mati","jalan memintas","jalan naik","jalan napas","jalan nasional","jalan ninja","jalan nordik","jalan parkir udara","jalan pedalaman","jalan pendekat","jalan pengaman","jalan pengantin","jalan penghubung","jalan pikiran","jalan pintas","jalan poros","jalan protokol","jalan provinsi","jalan rabat beton","jalan raya","Jalan Raya Pos","jalan rayap","jalan rel","jalan ronda","jalan salib","jalan samping","jalan santai","jalan sarad","jalan sehat","jalan serong","jalan setapak","jalan simpang","jalan simpang susun","jalan sutra","jalan tembus","jalan tengah","jalan terang","jalan terbuka","jalan tikus","jalan tol","jalan udara","jalan umum","jalan usaha tani","jalan usang","jalan utama","jalan-jalan","perjalanan waktu"]', '["ada jalan ke puncak gunung yang tinggi","adat sepanjang jalan, cupak sepanjang betung","alur bertempuh, jalan berturut","anggup-anggip bagai rumput di tengah jalan","banyak jalan menuju Roma","di mana ada kemauan, di sana ada jalan","jalan dialih orang lalu, cupak dipapak orang penggalas","jalan mati lagi dicoba, ini pula jalan binasa","jangan ditentang matahari condong, takut terturut jalan tak berintis","kasih ibu sepanjang jalan, kasih anak sepanjang penggalan","lancar kaji karena diulang, pasar jalan karena diturut","lebuh sempit kuda penyepak, jalan licin tebing berkelok","menganggungkan bagai rumput tengah jalan","pasar jalan karena diturut, lancar kaji karena diulang","searah bertukar jalan","sedepa jalan ke muka, setelempap jalan ke belakang","seiring bertukar jalan (sekandang tidak sebau, seia bertukar sebut)","seiring bertukar jalan, seia bertukar sebut","sesat di ujung jalan, balik ke pangkal jalan","sesat di ujung jalan, surut ke pangkal jalan","sudu-sudu di tepi jalan, dipanjat kena durinya, disinggung kena rabasnya, ditakik kena getahnya","tumbuh pada alur sudah diurut, tumbuh pada jalan sudah ditempuh"]', '["bagai sambau di tengah jalan (yang rebah bangun karena terinjak)","macam kepiting jalan","sumur (di) tepi jalan","tua di jalan"]', '[{"peribahasa":"ada jalan ke puncak gunung yang tinggi","makna":"Selalu ada cara atau solusi untuk mencapai tujuan yang sulit sekalipun."},{"peribahasa":"adat sepanjang jalan, cupak sepanjang betung","makna":"Setiap tempat atau daerah memiliki adat istiadat dan aturan yang berbeda-beda, yang harus dihormati dan diikuti."},{"peribahasa":"alur bertempuh, jalan berturut","makna":"Segala sesuatu harus dilakukan sesuai dengan aturan, prosedur, atau kebiasaan yang berlaku."},{"peribahasa":"anggup-anggip bagai rumput di tengah jalan","makna":"Seseorang yang tidak memiliki pendirian tetap, mudah terombang-ambing, atau selalu mengikuti ke mana angin bertiup."},{"peribahasa":"banyak jalan menuju Roma","makna":"Ada banyak cara atau metode untuk mencapai tujuan yang sama."},{"peribahasa":"di mana ada kemauan, di sana ada jalan","makna":"Jika seseorang memiliki keinginan yang kuat, ia akan selalu menemukan cara untuk mewujudkannya."},{"peribahasa":"jalan dialih orang lalu, cupak dipapak orang penggalas","makna":"Sesuatu yang sudah menjadi hak atau milik orang lain, tidak boleh diganggu gugat atau diambil."},{"peribahasa":"jalan mati lagi dicoba, ini pula jalan binasa","makna":"Seseorang yang nekat melakukan perbuatan yang sudah jelas berbahaya atau tidak mungkin berhasil, apalagi jika ditambah dengan tindakan lain yang lebih membahayakan lagi."},{"peribahasa":"jangan ditentang matahari condong, takut terturut jalan tak berintis","makna":"Jangan menentang atau melawan sesuatu yang sudah jelas akan terjadi atau sesuatu yang sudah menjadi takdir, karena akan membawa kerugian atau kesulitan."},{"peribahasa":"kasih ibu sepanjang jalan, kasih anak sepanjang penggalan","makna":"Kasih sayang seorang ibu kepada anaknya tidak terbatas, tulus, dan abadi, sedangkan kasih sayang anak kepada ibunya sering kali terbatas atau mudah dilupakan."},{"peribahasa":"lancar kaji karena diulang, pasar jalan karena diturut","makna":"Ilmu pengetahuan akan semakin dikuasai jika terus diulang-ulang, dan suatu usaha atau pekerjaan akan berjalan lancar jika diikuti dengan tekun."},{"peribahasa":"lebuh sempit kuda penyepak, jalan licin tebing berkelok","makna":"Menggambarkan suatu keadaan yang sangat sulit dan berbahaya, penuh dengan rintangan dan tantangan."},{"peribahasa":"menganggungkan bagai rumput tengah jalan","makna":"Memiliki makna yang sama dengan \"anggup-anggip bagai rumput di tengah jalan\"."},{"peribahasa":"pasar jalan karena diturut, lancar kaji karena diulang","makna":"Memiliki makna yang sama dengan \"lancar kaji karena diulang, pasar jalan karena diturut\"."},{"peribahasa":"searah bertukar jalan","makna":"Dua orang atau lebih yang memiliki tujuan yang sama, tetapi menempuh cara atau jalan yang berbeda."},{"peribahasa":"sedepa jalan ke muka, setelempap jalan ke belakang","makna":"Setiap langkah maju yang diambil harus diiringi dengan kewaspadaan dan pertimbangan terhadap kemungkinan risiko atau kemunduran."},{"peribahasa":"seiring bertukar jalan (sekandang tidak sebau, seia bertukar sebut)","makna":"Dua orang atau lebih yang awalnya bersama-sama, tetapi kemudian berpisah atau memiliki pandangan yang berbeda."},{"peribahasa":"seiring bertukar jalan, seia bertukar sebut","makna":"Memiliki makna yang sama dengan \"seiring bertukar jalan (sekandang tidak sebau, seia bertukar sebut)\"."},{"peribahasa":"sesat di ujung jalan, balik ke pangkal jalan","makna":"Jika terjadi kesalahan atau kekeliruan dalam suatu pekerjaan atau rencana, sebaiknya kembali ke awal untuk memperbaikinya."},{"peribahasa":"sesat di ujung jalan, surut ke pangkal jalan","makna":"Memiliki makna yang sama dengan \"sesat di ujung jalan, balik ke pangkal jalan\"."},{"peribahasa":"sudu-sudu di tepi jalan, dipanjat kena durinya, disinggung kena rabasnya, ditakik kena getahnya","makna":"Sesuatu yang terlihat sepele atau tidak berbahaya, tetapi sebenarnya memiliki banyak risiko atau kesulitan jika tidak ditangani dengan hati-hati."},{"peribahasa":"tumbuh pada alur sudah diurut, tumbuh pada jalan sudah ditempuh","makna":"Sesuatu yang sudah sesuai dengan aturan, kebiasaan, atau prosedur yang berlaku."}]');
