insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('33321', 'ja.ngan-ja.ngan', 'jangan-jangan', '', 'jangan', '["Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"barangkali; mungkin","contoh":[{"nomor":2,"teks":"dia tidak datang, ~ ada halangan di jalan"}]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('33316', 'ja.ngan', 'jangan', '', '', '["Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"kata yang menyatakan melarang, berarti tidak boleh; hendaknya tidak usah","contoh":[{"nomor":2,"teks":"-- bohong"}]}]', null, '["jangan-jangan","jangankan","menjangankan"]', '["jangan akan","jangan hendaknya","jangan sampai","jangan tiada"]', '["berbuat jahat jangan sekali, terbawa cemar segala ahli","biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","biar jatuh terletak, jangan jatuh terempas","biar mati anak asal jangan mati adat","biar mati anak, jangan mati adat","biar putih tulang, jangan putih mata","biar singit, jangan tertiarap","biar sipi (asal), jangan sesat","biar tersengat, jangan tiarap","biar titik, jangan tumpah","hilang di mata, di hati jangan","ikan biar dapat, serampang jangan pokah","ikan biar dapat, serampang jangan pukah","jangan dekatkan panggang dengan kucing","jangan dicatuk dengan yang tajam, cincang dengan yang majal","jangan dilepaskan tangan kanan, sebelum tangan kiri berpegang","jangan diperlebar timba ke perigi, kalau tak putus, genting","jangan diperlelarkan timba perigi, kalau tak putus genting","jangan ditentang matahari condong, takut terturut jalan tak berintis","jangan merempuh sarang lebah","jauh di mata, di hati jangan","jika takut dilimbur pasang, jangan berumah di tepi pantai","kalau kail panjang sejengkal, jangan laut hendak diduga","kalau menampi jangan tumpah padinya","kalau menyeberang sungai, biarlah ditelan oleh buaya, tetapi jangan dipagut oleh ikan kecil","kalau takut dilimbur pasang, jangan berumah di tepi pantai","kecil jangan disangka anak, besar jangan disangka bapa","kerbau jangan dimaling orang, ayam jangan dimusangi","ketika ada jangan dimakan, telah habis (tiada) maka dimakan","lagi ada jangan dimakan, sudah habis baru dimakan","lemak manis jangan ditelan, pahit jangan dimuntahkan","manis jangan lekas ditelan, pahit jangan lekas dimuntahkan","mara jangan dipukat, rezeki jangan ditolak","mulut manis jangan percaya, lepas dari tangan jangan diharap","musuh jangan dicari-cari, bersua jangan dielakkan","ombak yang kecil jangan diabaikan","orang kaya jangan diangan-angan, orang miskin jangan dihina","orang timpang jangan dicacat, ingat-ingat hari belakang","pelepah bawah luruh, pelepah atas jangan gelak","seberat-berat beban, laba jangan ditinggalkan","setapak jangan lalu, setapak jangan surut","tali jangan putus, kaitan jangan rekah","tangan kanan jangan percaya akan tangan kiri","tempat makan jangan dibenahi","usul-usul asal-asal, asal jangan ditinggalkan"]', '[]', '[{"peribahasa":"berbuat jahat jangan sekali, terbawa cemar segala ahli","makna":"Perbuatan jahat, meskipun dilakukan sekali, dapat mencemarkan nama baik seluruh keluarga atau kelompoknya."},{"peribahasa":"biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","makna":"Lebih baik mati daripada menanggung malu atau menyerah."},{"peribahasa":"biar jatuh terletak, jangan jatuh terempas","makna":"Lebih baik mengundurkan diri secara terhormat daripada diberhentikan dengan tidak hormat."},{"peribahasa":"biar mati anak asal jangan mati adat","makna":"Lebih baik mengorbankan anak daripada melanggar adat atau peraturan yang dipegang teguh."},{"peribahasa":"biar mati anak, jangan mati adat","makna":"Lebih baik mengorbankan anak daripada melanggar adat atau peraturan yang dipegang teguh."},{"peribahasa":"biar putih tulang, jangan putih mata","makna":"Lebih baik mati daripada menanggung malu atau menyerah."},{"peribahasa":"biar singit, jangan tertiarap","makna":"Lebih baik rugi sedikit daripada rugi banyak."},{"peribahasa":"biar sipi (asal), jangan sesat","makna":"Lebih baik rugi sedikit daripada rugi banyak."},{"peribahasa":"biar tersengat, jangan tiarap","makna":"Hendaklah diusahakan agar tidak terlanjur merugi."},{"peribahasa":"biar titik, jangan tumpah","makna":"Lebih baik mengalami kerugian kecil daripada kerugian besar."},{"peribahasa":"hilang di mata, di hati jangan","makna":"Meskipun seseorang telah pergi jauh atau tidak terlihat secara fisik, jangan pernah melupakan orang tersebut di dalam hati."},{"peribahasa":"ikan biar dapat, serampang jangan pokah","makna":"Maksud tercapai, perkakas pun tidak rusak; atau pekerjaan yang dibuat itu hendaklah mendapat faedah supaya jerih payah jangan hilang percuma."},{"peribahasa":"ikan biar dapat, serampang jangan pukah","makna":"Maksud tercapai, perkakas pun tidak rusak; atau pekerjaan yang dibuat itu hendaklah mendapat faedah supaya jerih payah jangan hilang percuma."},{"peribahasa":"jangan dekatkan panggang dengan kucing","makna":"Pemuda dan pemudi sebaiknya tidak dibiarkan bergaul terlalu rapat karena dapat menimbulkan hal-hal yang tidak diinginkan."},{"peribahasa":"jangan dicatuk dengan yang tajam, cincang dengan yang majal","makna":"Menasihati orang lain hendaknya dengan sabar dan berulang-ulang, bukan dengan perkataan yang kasar atau tajam."},{"peribahasa":"jangan dilepaskan tangan kanan, sebelum tangan kiri berpegang","makna":"Jangan melepaskan pekerjaan atau sesuatu yang sudah ada sebelum mendapatkan pengganti yang baru."},{"peribahasa":"jangan diperlebar timba ke perigi, kalau tak putus, genting","makna":"Jangan diulang-ulang perbuatan yang jahat, karena lambat laun akan mendapat bencana atau akibat buruk."},{"peribahasa":"jangan diperlelarkan timba perigi, kalau tak putus genting","makna":"Jangan diulang-ulang perbuatan yang jahat, karena lambat laun akan mendapat bencana atau akibat buruk."},{"peribahasa":"jangan ditentang matahari condong, takut terturut jalan tak berintis","makna":"Hendaknya berhati-hati dan waspada, jangan mudah terpedaya oleh sesuatu yang terlihat indah atau baik."},{"peribahasa":"jangan merempuh sarang lebah","makna":"Bahaya jangan dicari-cari."},{"peribahasa":"jauh di mata, di hati jangan","makna":"Meskipun tempat tinggal berjauhan, jangan sampai melupakan satu sama lain."},{"peribahasa":"jika takut dilimbur pasang, jangan berumah di tepi pantai","makna":"Jika takut akan kesulitan atau bahaya, sebaiknya jangan melakukan pekerjaan atau tindakan yang berisiko tinggi."},{"peribahasa":"kalau kail panjang sejengkal, jangan laut hendak diduga","makna":"Jika pengetahuan atau pengalaman masih sedikit, janganlah mencoba melawan atau menantang orang yang memiliki ilmu atau pengalaman yang jauh lebih banyak."},{"peribahasa":"kalau menampi jangan tumpah padinya","makna":"Berhati-hati dalam memilih atau membuat keputusan agar tidak membuang hal yang baik atau berguna."},{"peribahasa":"kalau menyeberang sungai, biarlah ditelan oleh buaya, tetapi jangan dipagut oleh ikan kecil","makna":"Lebih baik kalah kepada orang yang kuat daripada kalah kepada orang yang lemah; atau jika mendapat teguran atau hukuman, hendaklah datangnya dari yang berkuasa, bukan dari bawahan."},{"peribahasa":"kalau takut dilimbur pasang, jangan berumah di tepi pantai","makna":"Jika takut akan risiko atau kesulitan, sebaiknya jangan melakukan pekerjaan atau tindakan yang berpotensi menimbulkan bahaya atau kesusahan tersebut."},{"peribahasa":"kecil jangan disangka anak, besar jangan disangka bapa","makna":"Pengetahuan dan kelebihan tidak hanya dimiliki oleh orang yang sudah tua, tetapi juga bisa dimiliki oleh orang yang masih muda."},{"peribahasa":"kerbau jangan dimaling orang, ayam jangan dimusangi","makna":"Keluarga hendaklah dijaga dan dirawat dengan baik."},{"peribahasa":"ketika ada jangan dimakan, telah habis (tiada) maka dimakan","makna":"Seseorang harus hemat dan cermat dalam menjalani kehidupan, menabung saat memiliki kelebihan, dan baru menggunakan simpanan tersebut ketika benar-benar dalam keadaan terdesak."},{"peribahasa":"lagi ada jangan dimakan, sudah habis baru dimakan","makna":"Seseorang harus hemat dan cermat dalam menjalani kehidupan, menabung saat memiliki kelebihan, dan baru menggunakan simpanan tersebut ketika benar-benar dalam keadaan terdesak."},{"peribahasa":"lemak manis jangan ditelan, pahit jangan dimuntahkan","makna":"Perundingan atau nasihat yang baik jangan disia-siakan, tetapi hendaknya dipikirkan secara mendalam; dan suatu teguran keras, kritikan, dan celaan hendaknya tidak ditolak secara mentah-mentah."},{"peribahasa":"manis jangan lekas ditelan, pahit jangan lekas dimuntahkan","makna":"Perundingan atau nasihat yang baik jangan disia-siakan, tetapi hendaknya dipikirkan secara mendalam; dan suatu teguran keras, kritikan, dan celaan hendaknya tidak ditolak secara mentah-mentah."},{"peribahasa":"mara jangan dipukat, rezeki jangan ditolak","makna":"Jangan mencari-cari bahaya atau kecelakaan; dan rezeki, meskipun sedikit, haruslah diterima dengan syukur."},{"peribahasa":"mulut manis jangan percaya, lepas dari tangan jangan diharap","makna":"Jangan mudah percaya pada orang yang perkataannya manis atau pandai merayu, karena barang atau uang yang sudah dipinjamkan kepadanya kemungkinan besar tidak akan kembali."},{"peribahasa":"musuh jangan dicari-cari, bersua jangan dielakkan","makna":"Permusuhan sebaiknya tidak dicari-cari atau dimulai, tetapi jika permusuhan itu datang atau tidak dapat dihindari, janganlah takut atau menghindarinya."},{"peribahasa":"ombak yang kecil jangan diabaikan","makna":"Jangan memandang enteng atau meremehkan hal-hal kecil, karena seringkali hal-hal kecil dapat menimbulkan bahaya atau kesulitan di kemudian hari."},{"peribahasa":"orang kaya jangan diangan-angan, orang miskin jangan dihina","makna":"Tidak boleh terlalu mengharapkan atau mengagung-agungkan orang kaya, dan sebaliknya, tidak boleh merendahkan atau menghina orang miskin."},{"peribahasa":"orang timpang jangan dicacat, ingat-ingat hari belakang","makna":"Tidak boleh mencela atau membicarakan keburukan atau kecelakaan yang menimpa orang lain, karena nasib manusia tidaklah tetap dan bisa jadi suatu saat kita sendiri akan mengalami hal yang serupa."},{"peribahasa":"pelepah bawah luruh, pelepah atas jangan gelak","makna":"Harus ingat bahwa semua yang hidup pada akhirnya akan mati."},{"peribahasa":"seberat-berat beban, laba jangan ditinggalkan","makna":"Betapapun beratnya suatu pekerjaan, janganlah ditinggalkan karena suatu saat pasti akan memberikan keuntungan yang besar."},{"peribahasa":"setapak jangan lalu, setapak jangan surut","makna":"Pendirian harus kuat dan tidak mudah goyah."},{"peribahasa":"tali jangan putus, kaitan jangan rekah","makna":"Suatu perkara atau masalah harus diselesaikan dengan seadil-adilnya, sehingga kedua belah pihak yang bersengketa sama-sama merasa senang atau dapat menerimanya dengan lega."},{"peribahasa":"tangan kanan jangan percaya akan tangan kiri","makna":"Jangan terlalu percaya kepada sahabat karena sewaktu-waktu dia mungkin juga mencelakakan kita."},{"peribahasa":"tempat makan jangan dibenahi","makna":"Jangan berbuat jahat atau merusak kepada orang atau pihak yang telah memberikan kebaikan, rezeki, atau pertolongan."},{"peribahasa":"usul-usul asal-asal, asal jangan ditinggalkan","makna":"Dalam mengerjakan sesuatu, hendaklah dilakukan dengan sangat berhati-hati dan memperhatikan benar-benar sejak pekerjaan itu dimulai."}]');
