insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('33683', 'ja.tuh', 'jatuh', '', '', '["Verba","Verba","Verba","Verba","Verba","kiasan","Verba","kiasan","Verba","kiasan","Verba","Verba","Verba"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"(terlepas dan) turun atau meluncur ke bawah dengan cepat karena gravitasi bumi (baik ketika masih dalam gerakan turun maupun sesudah sampai ke tanah dan sebagainya)","contoh":[{"nomor":2,"teks":"tabung kaca itu -- dan hancur"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"turun banyak (harga, nilai, dan sebagainya); merosot","contoh":[{"nomor":2,"teks":"harga mobil di pasar bebas --"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"sampai ke ...; tiba di ...; kena pada ...; tembus ke ...; ditujukan ke","contoh":[{"nomor":2,"teks":"jalan kecil ini -- ke Kampung Ambon"},{"nomor":4,"teks":"sindiran itu --nya kepada saya"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"bertepatan dengan; berbetulan dengan; tepat pada","contoh":[{"nomor":2,"teks":"proklamasi kemerdekaan Republik Indonesia -- pada hari Jumat, tanggal 17 Agustus 1945"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"berhenti memegang kekuasaan (tentang pemerintah, kabinet, dan sebagainya)","contoh":[]},{"nomor":"6","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"bangkrut (tentang toko, kongsi, dan sebagainya)","contoh":[]},{"nomor":"7","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"kalah atau dirampas musuh (kota, benteng, dan sebagainya)","contoh":[]},{"nomor":"8","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak lulus (dalam ujian); gagal (dalam usaha); sangat menderita (rugi, sengsara, dan sebagainya)","contoh":[]},{"nomor":"9","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak tahan lagi (oleh godaan, penderitaan, cobaan, dan sebagainya)","contoh":[]},{"nomor":"10","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"menjadi (sakit, miskin, cinta, dan sebagainya)","contoh":[{"nomor":2,"teks":"-- miskin"}]}]', null, '["berjatuh","berjatuhan","jatuhan","kejatuhan","keterjatuhan","menjatuhi","menjatuhkan","penjatuh","penjatuhan","terjatuh"]', '["jatuh bangkrut","jatuh bangun","jatuh bebas","jatuh berkait","jatuh bertindih","jatuh cinta","jatuh coloknya","jatuh hati (kepada, akan)","jatuh iman","jatuh ke atas","jatuh ke bawah","jatuh merek","jatuh miskin","jatuh nama","jatuh pingsan","jatuh sakit","jatuh semangat","jatuh tapai","jatuh tekanan","jatuh tempo"]', '["acap melempar, akan jatuh jua","air cucuran atap jatuh ke pelimbahan juga","air mata jatuh ke perut","bagai batu jatuh ke lubuk","bagai bunyi cempedak jatuh","bagai garam jatuh ke air","barang tergenggam jatuh terlepas","biar jatuh terletak, jangan jatuh terempas","buah jatuh tak jauh dari pohonnya","bulu mata bagai seraut jatuh","busuk kerbau, jatuh berdebuk","daun dapat dilayangkan, getah jatuh ke perdu juga","daunnya jatuh melayang, buahnya jatuh ke pangkal juga","di mana kapak jatuh, di situ baji makan","hujan jatuh ke pasir","hujan tak sekali jatuh, simpai tak sekali erat","jatuh di atas tilam","jatuh diimpit tangga","jika benih yang baik jatuh ke laut, menjadi pulau","kalau pucuk sudah jatuh, baru bersua akarnya","kemiri jatuh ke pangkalnya","laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","lepas dari mulut harimau, jatuh ke mulut buaya","mempertinggi tempat jatuh, memperdalam tempat kena","mumbang jatuh, kelapa jatuh","orang penggamang mati jatuh","seperti tikus jatuh di beras","sudah dijolok, baru jatuh","sudah jatuh, ditimpa tangga"]', '["bulan jatuh dalam ribaan","jatuh bangun (2)","jatuh di kasur","jatuh dari langit","jatuh hati"]', '[{"peribahasa":"acap melempar, akan jatuh jua","makna":"Karena rajin, lambat laun berhasil jua."},{"peribahasa":"air cucuran atap jatuh ke pelimbahan juga","makna":"Sifat atau perilaku seorang anak biasanya akan mengikuti teladan orang tuanya."},{"peribahasa":"air mata jatuh ke perut","makna":"Berdukacita atau bersedih hati secara diam-diam, tanpa menunjukkan kesedihan tersebut kepada orang lain."},{"peribahasa":"bagai batu jatuh ke lubuk","makna":"Hilang lenyap atau hilang tanpa ada kabar berita lagi."},{"peribahasa":"bagai bunyi cempedak jatuh","makna":"Bunyi jatuh yang kuat."},{"peribahasa":"bagai garam jatuh ke air","makna":"Nasihat atau pelajaran yang mudah diterima atau cepat meresap."},{"peribahasa":"barang tergenggam jatuh terlepas","makna":"Sesuatu yang sudah dikuasai atau dimiliki, namun kemudian terlepas lagi atau hilang, sehingga menyebabkan kerugian atau kemalangan."},{"peribahasa":"biar jatuh terletak, jangan jatuh terempas","makna":"Lebih baik mengundurkan diri atau berhenti dari sesuatu atas kemauan sendiri, daripada diberhentikan atau dipecat dengan tidak hormat."},{"peribahasa":"buah jatuh tak jauh dari pohonnya","makna":"Sifat, tingkah laku, kebiasaan, atau bahkan fisik seorang anak tidak akan jauh berbeda dengan sifat, tingkah laku, kebiasaan, atau fisik orang tuanya."},{"peribahasa":"bulu mata bagai seraut jatuh","makna":"Orang kecil atau rendahan yang ingin meniru tingkah laku orang besar atau mampu, yang pada akhirnya membawa dirinya pada kekalahan atau kesulitan; atau menggambarkan orang yang sombong."},{"peribahasa":"busuk kerbau, jatuh berdebuk","makna":"Perbuatan yang kurang baik lambat laun akan diketahui orang lain juga."},{"peribahasa":"daun dapat dilayangkan, getah jatuh ke perdu juga","makna":"Kasih sayang yang diberikan kepada anak sendiri tidak sama atau tidak setara dengan kasih sayang yang diberikan kepada anak saudara atau anak orang lain."},{"peribahasa":"daunnya jatuh melayang, buahnya jatuh ke pangkal juga","makna":"Seseorang yang tidak berbudi pekerti, meskipun memiliki banyak pengetahuan, pada akhirnya akan ketahuan juga asal-usulnya; yang berguna akan tetap tinggal, sedangkan yang tidak berguna akan terbuang."},{"peribahasa":"di mana kapak jatuh, di situ baji makan","makna":"Di mana suatu perkara atau permasalahan timbul, di situlah permasalahan tersebut harus diselesaikan."},{"peribahasa":"hujan jatuh ke pasir","makna":"Kebaikan yang tidak terbalas; nasihat yang diberi tidak berbekas; atau berbuat baik tidak pada tempatnya."},{"peribahasa":"hujan tak sekali jatuh, simpai tak sekali erat","makna":"Suatu pekerjaan tidak dapat diselesaikan sekaligus atau dalam satu waktu; atau keberuntungan dan kebahagiaan tidak datang semuanya secara sekaligus."},{"peribahasa":"jatuh di atas tilam","makna":"Mendapatkan keberuntungan atau kesenangan hidup."},{"peribahasa":"jatuh diimpit tangga","makna":"Mendapatkan musibah atau kesusahan secara beruntun atau bertubi-tubi."},{"peribahasa":"jika benih yang baik jatuh ke laut, menjadi pulau","makna":"Seseorang yang memiliki sifat atau keturunan yang baik, di mana pun ia berada atau dalam kondisi apa pun, akan tetap menunjukkan kebaikan dan kualitasnya."},{"peribahasa":"kalau pucuk sudah jatuh, baru bersua akarnya","makna":"Seseorang baru akan menyadari penyebab atau akar permasalahan setelah suatu kejadian buruk atau kegagalan telah terjadi."},{"peribahasa":"kemiri jatuh ke pangkalnya","makna":"Beroleh tempat yang pantas atau kembali ke tempat asalnya."},{"peribahasa":"laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","makna":"Orang yang belum mantap kedudukannya atau belum bernasib baik dalam mengadu untung; atau hidup melarat di negeri asing/rantauan."},{"peribahasa":"lepas dari mulut harimau, jatuh ke mulut buaya","makna":"Lepas dari bahaya yang besar, lalu jatuh ke dalam bahaya yang lebih besar lagi."},{"peribahasa":"mempertinggi tempat jatuh, memperdalam tempat kena","makna":"Sengaja membesar-besarkan kesalahan sendiri sehingga mendapat hukuman (kerugian) yang lebih berat."},{"peribahasa":"mumbang jatuh, kelapa jatuh","makna":"Setiap yang bernyawa akan mati juga, tidak memandang usia."},{"peribahasa":"orang penggamang mati jatuh","makna":"Celaka dapat timbul justru akibat ketakutan atau kecemasan yang berlebihan; atau orang yang takut-takut tidak akan mencapai kehendaknya atau maksudnya."},{"peribahasa":"seperti tikus jatuh di beras","makna":"Suka dan senang sekali karena beroleh keuntungan ataupun rezeki; atau mendapatkan keuntungan tanpa diketahui oleh orang lain."},{"peribahasa":"sudah dijolok, baru jatuh","makna":"Sesuatu perkara itu hanya akan berlaku atau seseorang itu hanya akan bertindak setelah didesak, dipaksa, atau diberikan dorongan."},{"peribahasa":"sudah jatuh, ditimpa tangga","makna":"Mengalami kemalangan atau kesulitan yang beruntun."}]');
