insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('33716', 'ja.uh', 'jauh', '', '', '["Adjektiva","Adjektiva","Adjektiva","Adjektiva","Adjektiva","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"panjang antaranya (jaraknya); tidak dekat","contoh":[{"nomor":2,"teks":"rumah kami -- dari pasar"},{"nomor":4,"teks":"ia berasal dari tempat yang --"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"banyak sekali; amat; sangat (tentang perbedaan, selisih atau kekurangan)","contoh":[{"nomor":2,"teks":"anak itu -- lebih besar daripada kakaknya"}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"belum sampai kepada yang dimaksudkan (ditetapkan)","contoh":[{"nomor":2,"teks":"tawaranmu masih --"}]},{"nomor":"4","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"sangat kurang","contoh":[{"nomor":2,"teks":"keadaannya masih -- dari sempurna"}]},{"nomor":"5","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"lanjut (tentang usia)","contoh":[{"nomor":2,"teks":"sudah -- umur ayah"}]},{"nomor":"6","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"renggang; tidak rapat (tentang persahabatan)","contoh":[{"nomor":2,"teks":"sanak saudara yang --"}]}]', null, '["berjauh","berjauh-jauhan","berjauhan","jauh-jauhan","kejauhan","memperjauh","menjauh","menjauhi","menjauhkan","penjauhan","sejauh","terjauh","terjauhkan"]', '["jauh di mata","jauh hari","jauh malam","jauh rezekinya"]', '["acap berulang, yang jauh jadi dekat","berbuat baik berpada-pada, berbuat jahat jauh sekali","buah jatuh tak jauh dari pohonnya","dekat dapat ditunjal, jauh dapat ditunjuk","dekat mencari indu, jauh mencari suku","dekat mencari induk, jauh mencari suku","dekat mencari suku, jauh mencari hindu","dekat tak berantara, jauh tak bersuatu","dekat tak tercapai, jauh tak antara","dekat tak tercapai, jauh tak berantara","dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","jauh bau bunga, dekat bau tahi","jauh berjalan banyak dilihat, lama hidup banyak dirasa","jauh berjalan, banyak dilihat","jauh dapat ditunjuk, dekat dapat ditunjal","jauh di mata, dekat di hati","jauh di mata, di hati jangan","jauh menyalak kuat, dekat mencawat ekor","jauh panggang dari api","obat jauh, penyakit hampir","pandang jauh dilayangkan, pandang dekat ditukikkan","panjang akar jauh belitnya","pendekar elak jauh","rebung tidak jauh dari rumpun","sayap singkat, terbang hendak jauh","tak jauh rebung dari rumpunnya","yang tinggi tampak jauh, yang dekat jolong bersua"]', '["main kurang jauh"]', '[{"peribahasa":"acap berulang, yang jauh jadi dekat","makna":"Sesuatu yang awalnya terasa jauh atau sulit, lama-kelamaan akan menjadi dekat atau mudah karena sering dilakukan atau sering bertemu."},{"peribahasa":"berbuat baik berpada-pada, berbuat jahat jauh sekali","makna":"Jika ingin melakukan perbuatan baik, janganlah berlebihan; dan perbuatan jahat harus dihindari sama sekali atau jangan pernah dicoba."},{"peribahasa":"buah jatuh tak jauh dari pohonnya","makna":"Sifat, tingkah laku, kebiasaan, atau bahkan fisik seorang anak tidak akan jauh berbeda dengan sifat, tingkah laku, kebiasaan, atau fisik orang tuanya."},{"peribahasa":"dekat dapat ditunjal, jauh dapat ditunjuk","makna":"Suatu perkataan, pengakuan, atau persaksian dapat dibuktikan kebenarannya."},{"peribahasa":"dekat mencari indu, jauh mencari suku","makna":"Jika merantau ke tempat yang dekat, kita mencari orang yang seketurunan; jika merantau ke tempat yang jauh, kita mencari orang yang satu suku untuk dijadikan saudara atau tempat bergantung."},{"peribahasa":"dekat mencari induk, jauh mencari suku","makna":"Jika merantau ke tempat yang dekat, kita mencari orang yang seketurunan; jika merantau ke tempat yang jauh, kita mencari orang yang satu suku untuk dijadikan saudara atau tempat bergantung."},{"peribahasa":"dekat mencari suku, jauh mencari hindu","makna":"Mencari pertalian keluarga atau menyusur galur; atau ketika merantau masih dekat, yang menjadi saudara adalah orang yang seinduk, tetapi jika tempat merantau sudah jauh, orang sesuku pun sudah cukup menjadi saudara."},{"peribahasa":"dekat tak berantara, jauh tak bersuatu","makna":"Sesuatu yang sangat diinginkan atau dekat di mata, tetapi tidak mampu untuk didapatkan atau dicapai."},{"peribahasa":"dekat tak tercapai, jauh tak antara","makna":"Sesuatu yang sebenarnya dekat untuk dicapai, namun tidak ada daya upaya atau kemampuan untuk meraihnya."},{"peribahasa":"dekat tak tercapai, jauh tak berantara","makna":"Sesuatu yang sebenarnya dekat untuk dicapai, namun tidak ada daya upaya atau kemampuan untuk meraihnya."},{"peribahasa":"dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","makna":"Diumpat atau dicaci maki karena perilaku yang tidak senonoh; atau jika seseorang berbuat salah, ia akan diumpat orang di belakang jika tidak di depan."},{"peribahasa":"jauh bau bunga, dekat bau tahi","makna":"Sanak saudara atau kerabat, jika berjauhan akan selalu terkenang dan dirindukan, tetapi jika berdekatan justru sering bertengkar atau berselisih paham."},{"peribahasa":"jauh berjalan banyak dilihat, lama hidup banyak dirasa","makna":"Seseorang yang banyak bepergian atau mengembara dan telah hidup lama, tentu memiliki banyak pengalaman dan pandangan yang luas."},{"peribahasa":"jauh berjalan, banyak dilihat","makna":"Seseorang yang banyak bepergian atau mengembara dan telah hidup lama, tentu memiliki banyak pengalaman dan pandangan yang luas."},{"peribahasa":"jauh dapat ditunjuk, dekat dapat ditunjal","makna":"Suatu perkataan, pengakuan, atau persaksian dapat dibuktikan kebenarannya."},{"peribahasa":"jauh di mata, dekat di hati","makna":"Meskipun terpisah jarak, namun tetap dekat di hati; selalu teringat dan terkenang."},{"peribahasa":"jauh di mata, di hati jangan","makna":"Meskipun seseorang telah pergi jauh atau tidak terlihat secara fisik, jangan pernah melupakan orang tersebut di dalam hati."},{"peribahasa":"jauh menyalak kuat, dekat mencawat ekor","makna":"Berbicara sombong atau berani di belakang, tetapi menjadi takut atau takluk ketika berhadapan langsung."},{"peribahasa":"jauh panggang dari api","makna":"Tindakan yang tidak sesuai dengan maksudnya; tawaran yang jauh di bawah harga; atau tidak kena atau tidak tepat (tentang jawaban, sindiran)."},{"peribahasa":"obat jauh, penyakit hampir","makna":"Dalam kesusahan, sukar mendapatkan pertolongan; atau berada dalam kesukaran."},{"peribahasa":"pandang jauh dilayangkan, pandang dekat ditukikkan","makna":"Menyelidiki atau memeriksa sesuatu secara teliti dan cermat."},{"peribahasa":"panjang akar jauh belitnya","makna":"Seseorang yang memiliki banyak akal atau rencana, biasanya sulit dipatahkan atau ditandingi; juga dapat berarti masalah yang rumit dan berliku-liku sehingga membutuhkan waktu dan usaha besar untuk menyelesaikannya."},{"peribahasa":"pendekar elak jauh","makna":"Orang yang sangat berhati-hati dan senantiasa bersiap mengelakkan bahaya yang mengancam."},{"peribahasa":"rebung tidak jauh dari rumpun","makna":"Sifat atau perilaku seorang anak tidak jauh berbeda dengan sifat atau perilaku orang tuanya."},{"peribahasa":"sayap singkat, terbang hendak jauh","makna":"Hendak berbuat sesuatu yang melebihi kemampuan atau kekuasaan."},{"peribahasa":"tak jauh rebung dari rumpunnya","makna":"Sifat atau perilaku seorang anak tidak jauh berbeda dengan sifat atau perilaku orang tuanya."},{"peribahasa":"yang tinggi tampak jauh, yang dekat jolong bersua","makna":"Dalam suatu usaha atau pekerjaan, pemimpinlah yang bertanggung jawab dan dia pulalah yang akan dipuji ataupun dicela."}]');
