insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('17679', 'jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)', 'jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)', 'peribahasa', 'dandang²', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"menggunakan segala daya upaya untuk mencapai maksud","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('60078', 'jika takut dilimbur pasang, jangan berumah di tepi pantai', 'jika takut dilimbur pasang, jangan berumah di tepi pantai', 'peribahasa', 'pantai', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"kalau takut mendapat kesusahan, jangan mengerjakan hal-hal yang berbahaya","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('70607', 'jika tidak pecah ruyung, di mana boleh mendapat sagu', 'jika tidak pecah ruyung, di mana boleh mendapat sagu', 'peribahasa', 'ruyung¹', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"tidak akan tercapai maksud kalau tidak mau berusaha","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('34597', 'ji.ka', 'jika', '', '', '["Partikel"]', '[{"nomor":"1","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"kata penghubung untuk menandai syarat (janji); kalau","contoh":[{"nomor":2,"teks":"-- hari tidak hujan, saya akan datang"},{"nomor":4,"teks":"intan itu -- terbenam di pelimbahan sekalipun tiada akan hilang cahayanya"}]}]', null, '[]', '[]', '["adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","belakang parang lagi jika diasah niscaya tajam","jika belalang ada seekor, jika emas ada miang","jika benih yang baik jatuh ke laut, menjadi pulau","jika kasih akan padi, buanglah rumput","jika langkah sudah terlangkahkan, berpantang dihela surut","jika pisau tiada berbaja, makin dikikir bertambah tumpul","jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","jika takut dilimbur pasang, jangan berumah di tepi pantai","jika tiada tersapu arang di muka, baiklah mati daripada hidup","jika tidak pecah ruyung, di mana boleh mendapat sagu","madu satu tong, jika rembes, rembesnya pun madu jua","punggung parang sekalipun jika selalu diasah, akan tajam juga","seperti orang mati, jika tiada orang mengangkat, bila akan bergerak"]', '[]', '[{"peribahasa":"adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","makna":"Orang yang memiliki sifat atau budi pekerti yang baik, meskipun ia berada dalam keadaan sulit, miskin, atau bergaul dengan orang yang tidak baik, sifat baiknya tidak akan hilang atau berubah."},{"peribahasa":"belakang parang lagi jika diasah niscaya tajam","makna":"Meskipun seseorang itu bodoh atau kurang pandai, jika ia mau belajar dengan sungguh-sungguh dan gigih, niscaya ia akan menjadi pandai juga."},{"peribahasa":"jika belalang ada seekor, jika emas ada miang","makna":"Segala sesuatu ada aturannya sendiri atau tiap-tiap suatu itu ada maknanya pasangannya."},{"peribahasa":"jika benih yang baik jatuh ke laut, menjadi pulau","makna":"Seseorang yang memiliki sifat atau keturunan yang baik, di mana pun ia berada atau dalam kondisi apa pun, akan tetap menunjukkan kebaikan dan kualitasnya."},{"peribahasa":"jika kasih akan padi, buanglah rumput","makna":"Jika kita menyayangi anak istri, maka berhentilah mengasihi atau menjalin hubungan dengan perempuan lain."},{"peribahasa":"jika langkah sudah terlangkahkan, berpantang dihela surut","makna":"Suatu pekerjaan atau keputusan yang telah dimulai dengan sungguh-sungguh, tidak boleh dihentikan sebelum tujuan tercapai."},{"peribahasa":"jika pisau tiada berbaja, makin dikikir bertambah tumpul","makna":"Orang yang dungu, makin diajar semakin bodoh."},{"peribahasa":"jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","makna":"Menggunakan segala daya upaya untuk mencapai maksud atau tujuan."},{"peribahasa":"jika takut dilimbur pasang, jangan berumah di tepi pantai","makna":"Jika takut akan risiko atau kesulitan, sebaiknya jangan melakukan pekerjaan atau tindakan yang berpotensi menimbulkan bahaya atau kesusahan tersebut."},{"peribahasa":"jika tiada tersapu arang di muka, baiklah mati daripada hidup","makna":"Lebih baik mati daripada hidup dengan menanggung malu yang teramat sangat."},{"peribahasa":"jika tidak pecah ruyung, di mana boleh mendapat sagu","makna":"Suatu maksud atau tujuan tidak akan pernah tercapai jika tidak mau berusaha atau bersusah payah."},{"peribahasa":"madu satu tong, jika rembes, rembesnya pun madu jua","makna":"Jika seseorang berasal dari keturunan yang baik, maka perilakunya juga akan baik; atau jika asalnya baik, turunannya pun akan baik juga."},{"peribahasa":"punggung parang sekalipun jika selalu diasah, akan tajam juga","makna":"Orang yang kurang pandai sekalipun, jika terus belajar dan berusaha dengan gigih, pada akhirnya akan menjadi pandai juga."},{"peribahasa":"seperti orang mati, jika tiada orang mengangkat, bila akan bergerak","makna":"Seseorang yang sangat lemah atau tidak berdaya, jika tidak ada yang menolongnya, maka ia akan semakin kesulitan atau tidak akan bisa berbuat apa-apa."}]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('30380', 'jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga', 'jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga', 'peribahasa', 'hulu', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"jika seseorang jahat asalnya, jahat juga kelakuannya","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('84579', 'jikalau tidak berada-ada (ada berada, ada mengada), masakan tempua bersarang rendah', 'jikalau tidak berada-ada (ada berada, ada mengada), masakan tempua bersarang rendah', 'peribahasa', 'tempua', '[]', '[{"nomor":"1","kelasKata":[],"definisi":"jika tidak ada sebab-sebabnya (sesuatu yang tersembunyi), tentu tidak akan terjadi yang luar biasa","contoh":[]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('34598', 'ji.ka.lau', 'jikalau', '', '', '["Partikel"]', '[{"nomor":"1","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"kalau; jika","contoh":[]}]', null, '[]', '[]', '["apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","arang itu jikalau dibasuh dengan air mawar sekalipun, tiada akan putih","jikalau beranak, ikut kata bidan","jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga","jikalau tidak berada-ada (ada berada, ada mengada), masakan tempua bersarang rendah","jikalau tidak dapat diperbaiki, janganlah dipecahkan"]', '[]', '[{"peribahasa":"apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","makna":"Tidak ada faedahnya menunjukkan kepandaian atau kelebihan diri kepada orang-orang yang tidak dapat menghargainya atau tidak mengerti."},{"peribahasa":"arang itu jikalau dibasuh dengan air mawar sekalipun, tiada akan putih","makna":"Sifat atau tabiat buruk seseorang yang sudah mendarah daging tidak akan bisa diubah atau diperbaiki, meskipun dengan berbagai cara atau nasihat."},{"peribahasa":"jikalau beranak, ikut kata bidan","makna":"Turutilah nasihat orang yang lebih ahli/bijak daripada kita."},{"peribahasa":"jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga","makna":"Jika seseorang jahat asalnya, jahat juga kelakuannya; atau jika dari mula sudah kusut maka sukarlah untuk menyelesaikan."},{"peribahasa":"jikalau tidak berada-ada (ada berada, ada mengada), masakan tempua bersarang rendah","makna":"Segala sesuatu pasti ada sebabnya (ada sesuatu yang tersembunyi) sehingga terjadi demikian."},{"peribahasa":"jikalau tidak dapat diperbaiki, janganlah dipecahkan","makna":"Jika sesuatu tidak dapat diperbaiki atau diselesaikan, janganlah dirusak atau diperparah keadaannya."}]');
